import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void tenDigits() {
        assertEquals("******7890", new Solution().maskAccountNumber("1234567890"));
    }

    @Test
    void exactlyFour() {
        // length == 4: return unchanged
        assertEquals("1234", new Solution().maskAccountNumber("1234"));
    }

    @Test
    void fiveDigits() {
        // only the first digit is masked
        assertEquals("*2345", new Solution().maskAccountNumber("12345"));
    }

    @Test
    void eightDigits() {
        assertEquals("****5678", new Solution().maskAccountNumber("12345678"));
    }

    @Test
    void threeDigits() {
        // length < 4: return unchanged
        assertEquals("123", new Solution().maskAccountNumber("123"));
    }

    @Test
    void empty() {
        assertEquals("", new Solution().maskAccountNumber(""));
    }

    @Test
    void sixteenDigits() {
        // typical credit card length
        assertEquals("************3456", new Solution().maskAccountNumber("1234567890123456"));
    }
}
